  </style>
</head>
<body class="min-h-screen flex flex-col p-4 md:p-6 bg-white selection:bg-[#d3e3fd]">

  <!-- Workspace Header -->
  <header class="flex flex-col sm:flex-row sm:items-center sm:justify-between border-b border-[#747775] border-opacity-20 pb-4 mb-6 gap-4">
    <div class="flex items-center gap-3">
      <!-- M3 Board Icon -->
      <div class="w-10 h-10 rounded-lg bg-[#d3e3fd] flex items-center justify-center text-[#0b57d0]">
        <svg class="w-6 h-6" fill="currentColor" viewBox="0 0 24 24">
          <path d="M19 3H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V5c0-1.1-.9-2-2-2zm-9 14H5v-2h5v2zm0-4H5v-2h5v2zm0-4H5V7h5v2zm9 8h-7v-2h7v2zm0-4h-7v-2h7v2zm0-4h-7V7h7v2z"/>
        </svg>
      </div>
      <div>
        <h1 class="text-xl font-medium tracking-tight text-gray-900" id="workspace-title">Sojo Task Board</h1>
        <p class="text-xs text-gray-500 font-normal mt-0.5" id="workspace-subtitle">Live collaborative workspace tracking</p>
      </div>
    </div>

    <!-- Real Workspace Team Members Indicator -->
    <div class="flex items-center gap-2 bg-[#f0f4f9] px-3 py-1.5 rounded-full border border-gray-100">
      <span class="text-[11px] text-gray-500 font-medium mr-1 uppercase tracking-wider">Workspace Team:</span>
      <div class="flex -space-x-1.5 overflow-hidden" id="collaborators-list">
        <!-- Rendered dynamically -->
      </div>
    </div>
  </header>

  <!-- Kanban Grid Area -->
  <main class="grid grid-cols-1 md:grid-cols-3 gap-5 flex-grow items-start">

    <!-- To Do Column -->
    <section class="bg-[#f0f4f9] rounded-xl p-4 flex flex-col min-h-[450px] border border-gray-200 border-opacity-50">
      <div class="flex items-center justify-between mb-4 px-1">
        <h3 class="text-[15px] font-medium text-gray-700 tracking-tight">To Do</h3>
        <span id="todo-count" class="text-xs bg-[#d3e3fd] text-[#0b57d0] px-2.5 py-0.5 rounded-full font-medium">0</span>
      </div>
      <div id="todo-cards" class="flex flex-col gap-3 flex-grow overflow-y-auto">
        <!-- Tasks -->
      </div>
      <div id="todo-form-container" class="mt-3">
        <button onclick="showAddForm('To Do')" class="w-full text-left text-xs text-[#0b57d0] hover:bg-white hover:bg-opacity-75 p-2 rounded-lg flex items-center gap-1.5 transition font-medium">
          <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 4v16m8-8H4"/>
          </svg>
          Add task
        </button>
      </div>
    </section>

    <!-- In Progress Column -->
    <section class="bg-[#f0f4f9] rounded-xl p-4 flex flex-col min-h-[450px] border border-gray-200 border-opacity-50">
      <div class="flex items-center justify-between mb-4 px-1">
        <h3 class="text-[15px] font-medium text-gray-700 tracking-tight">In Progress</h3>
        <span id="inprogress-count" class="text-xs bg-[#d3e3fd] text-[#0b57d0] px-2.5 py-0.5 rounded-full font-medium">0</span>
      </div>
      <div id="inprogress-cards" class="flex flex-col gap-3 flex-grow overflow-y-auto">
        <!-- Tasks -->
      </div>
      <div id="inprogress-form-container" class="mt-3">
        <button onclick="showAddForm('In Progress')" class="w-full text-left text-xs text-[#0b57d0] hover:bg-white hover:bg-opacity-75 p-2 rounded-lg flex items-center gap-1.5 transition font-medium">
          <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 4v16m8-8H4"/>
          </svg>
          Add task
        </button>
      </div>
    </section>

    <!-- Done Column -->
    <section class="bg-[#f0f4f9] rounded-xl p-4 flex flex-col min-h-[450px] border border-gray-200 border-opacity-50">
      <div class="flex items-center justify-between mb-4 px-1">
        <h3 class="text-[15px] font-medium text-gray-700 tracking-tight">Done</h3>
        <span id="done-count" class="text-xs bg-[#d3e3fd] text-[#0b57d0] px-2.5 py-0.5 rounded-full font-medium">0</span>
      </div>
      <div id="done-cards" class="flex flex-col gap-3 flex-grow overflow-y-auto">
        <!-- Tasks -->
      </div>
      <div id="done-form-container" class="mt-3">
        <button onclick="showAddForm('Done')" class="w-full text-left text-xs text-[#0b57d0] hover:bg-white hover:bg-opacity-75 p-2 rounded-lg flex items-center gap-1.5 transition font-medium">
          <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 4v16m8-8H4"/>
          </svg>
          Add task
        </button>
      </div>
    </section>

  </main>

  <script>
    // Injected environment variables support
    const envId = window.__sandboxEnvId;
    const workspaceName = window.__sandboxWorkspaceName;
    const syncKey = "sojo_kanban_board_state_final";

    // Update Workspace metadata titles if available
    if (workspaceName) {
      document.getElementById('workspace-title').textContent = `${workspaceName} Kanban`;
      document.getElementById('workspace-subtitle').textContent = "Real-time Google Workspace coordination";
    }

    // MANDATORY TEAM MEMBERS
    const TEAM_MEMBERS = [
      { name: "Carlin Yuen", email: "carlinyuen@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjXiCLyI7uRQYGSlcqlHsXaV7f29imvyNIMx6Ol02M-HKrN-e2XDwA=s64" },
      { name: "Boqing Xue", email: "boqing@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjXPQ8dBIt0XpUp4hqnBFrhL46Bb_WifrVamA_a8xlHMez3nvo3W=s64" },
      { name: "Alan McLean", email: "alanmclean@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjVvL9iU15212-njBswd2d3iJe7cqCK47OrJwhkB5dJ1HJRl58s=s64" },
      { name: "Mirjam van Esch", email: "mirjamvanesch@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjXTBbC9f6t0nk1AnwJs5rlbhjpfVQxK2sM8PqQXbNVAx3YKh4LMVA=s64" }
    ];

    // INITIAL TASK DEFAULTS MAPPED FROM ACTIVE TEAM DISCUSSIONS
    const INITIAL_TASKS = [
      { id: "task-1", title: "Define 'Task' primitive structure specifying state, goal & outcomes", status: "Done", assignee: "boqing@google.com" },
      { id: "task-2", title: "Incorporate market data, SMB growth metrics and sizing into Pitch Deck", status: "In Progress", assignee: "alanmclean@google.com" },
      { id: "task-3", title: "Refine Jet Ski end-to-end prototype for Friday review session", status: "In Progress", assignee: "carlinyuen@google.com" },
      { id: "task-4", title: "Analyze Sojo steering feedback & layout custom interaction rules", status: "To Do", assignee: "mirjamvanesch@google.com" },
      { id: "task-5", title: "Confirm CLI connection policies and test System Compatibility", status: "To Do", assignee: "carlinyuen@google.com" }
    ];

    let currentTasks = [];

    // Initialize team indicators
    function renderCollaborators() {
      const container = document.getElementById('collaborators-list');
      container.innerHTML = TEAM_MEMBERS.map(m => `
        <img src="${m.avatar}" alt="${m.name}" title="${m.name} (${m.email})" class="w-6 h-6 rounded-full border-2 border-white object-cover">
      `).join('');
    }

    // Helper to resolve assignee records
    function getAssignee(email) {
      return TEAM_MEMBERS.find(m => m.email === email) || {
        name: "Unassigned",
        avatar: "data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='%23747775'><path d='M12 12c2.21 0 4-1.79 4-4s-1.79-4-4-4-4 1.79-4 4 1.79 4 4 4zm0 2c-2.67 0-8 1.34-8 4v2h16v-2c0-2.66-5.33-4-8-4z'/></svg>"
      };
    }

    // Main sync state load
    async function loadSyncedState() {
      if (!envId) {
        if (currentTasks.length === 0) {
          currentTasks = [...INITIAL_TASKS];
          renderBoard();
        }
        return;
      }
      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`);
        const json = await res.json();
        if (json.data && Array.isArray(json.data)) {
          const stateStr = JSON.stringify(json.data);
          if (stateStr !== JSON.stringify(currentTasks)) {
            currentTasks = json.data;
            renderBoard();
          }
        } else {
          currentTasks = [...INITIAL_TASKS];
          await saveSyncedState(currentTasks);
          renderBoard();
        }
      } catch (err) {
        console.error("Failed to load synced state:", err);
        if (currentTasks.length === 0) {
          currentTasks = [...INITIAL_TASKS];
          renderBoard();
        }
      }
    }

    // Save state back to flat-file sync database
    async function saveSyncedState(newState) {
      currentTasks = newState;
      renderBoard();
      if (!envId) return;
      try {
        await fetch(`/api/sync/${envId}/${syncKey}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ data: newState })
        });
      } catch (err) {
        console.error("Failed to save synced state:", err);
      }
    }

    // Dynamic Board UI Renderer
    function renderBoard() {
      const todoCards = document.getElementById('todo-cards');
      const inprogressCards = document.getElementById('inprogress-cards');
      const doneCards = document.getElementById('done-cards');

      todoCards.innerHTML = '';
      inprogressCards.innerHTML = '';
      doneCards.innerHTML = '';

      let counts = { 'To Do': 0, 'In Progress': 0, 'Done': 0 };

      currentTasks.forEach(task => {
        const assignee = getAssignee(task.assignee);
        const cardHtml = `
          <div class="bg-white rounded-lg border border-[#747775] border-opacity-20 p-3 hover:border-opacity-50 transition flex flex-col gap-2.5 shadow-sm">
            <div class="text-[13px] text-[#1f1f1f] leading-normal break-words font-normal">
              ${task.title}
            </div>
            <div class="flex items-center justify-between pt-1.5 border-t border-[#e0e0e0] border-opacity-50">
              <div class="flex items-center gap-1.5 overflow-hidden">
                <img src="${assignee.avatar}" alt="${assignee.name}" class="w-5 h-5 rounded-full object-cover">
                <span class="text-[11px] text-[#5f6368] truncate font-medium">${assignee.name}</span>
              </div>
              <div class="flex items-center gap-1">
                ${task.status !== 'To Do' ? `
                  <button onclick="moveTask('${task.id}', 'prev')" class="p-1 hover:bg-gray-100 rounded text-gray-500 hover:text-[#0b57d0] transition" title="Move left">
                    <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2.5" d="M15 19l-7-7 7-7"/></svg>
                  </button>
                ` : ''}
                ${task.status !== 'Done' ? `
                  <button onclick="moveTask('${task.id}', 'next')" class="p-1 hover:bg-gray-100 rounded text-gray-500 hover:text-[#0b57d0] transition" title="Move right">
                    <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2.5" d="M9 5l7 7-7 7"/></svg>
                  </button>
                ` : ''}
                <button onclick="deleteTask('${task.id}')" class="p-1 hover:bg-red-50 rounded text-gray-400 hover:text-[#b3261e] transition ml-0.5" title="Delete task">
                  <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                </button>
              </div>
            </div>
          </div>
        `;

        if (task.status === 'To Do') {
          todoCards.insertAdjacentHTML('beforeend', cardHtml);
          counts['To Do']++;
        } else if (task.status === 'In Progress') {
          inprogressCards.insertAdjacentHTML('beforeend', cardHtml);
          counts['In Progress']++;
        } else if (task.status === 'Done') {
          doneCards.insertAdjacentHTML('beforeend', cardHtml);
          counts['Done']++;
        }
      });

      document.getElementById('todo-count').textContent = counts['To Do'];
      document.getElementById('inprogress-count').textContent = counts['In Progress'];
      document.getElementById('done-count').textContent = counts['Done'];
    }

    // Form Interactions
    function showAddForm(status) {
      const containerId = status === 'To Do' ? 'todo-form-container' : (status === 'In Progress' ? 'inprogress-form-container' : 'done-form-container');
      const container = document.getElementById(containerId);

      container.innerHTML = `
        <div class="bg-white rounded-lg border border-[#747775] border-opacity-20 p-3 flex flex-col gap-2.5 shadow-sm">
          <textarea id="new-task-title-${status}" rows="2" placeholder="Task title..." class="w-full text-xs p-2 border border-gray-300 rounded focus:outline-none focus:border-[#0b57d0] resize-none font-sans" required></textarea>
          <div class="flex flex-col gap-1">
            <label class="text-[10px] text-gray-500 font-medium">Assignee</label>
            <select id="new-task-assignee-${status}" class="w-full text-xs p-1.5 border border-gray-300 rounded bg-white text-gray-700 font-sans focus:outline-none focus:border-[#0b57d0]">
              ${TEAM_MEMBERS.map(m => `<option value="${m.email}">${m.name}</option>`).join('')}
            </select>
          </div>
          <div class="flex justify-end gap-1.5 mt-1">
            <button onclick="hideAddForm('${status}')" class="px-2.5 py-1 text-xs font-medium text-gray-600 hover:bg-gray-100 rounded transition">Cancel</button>
            <button onclick="submitNewTask('${status}')" class="px-3 py-1 text-xs font-medium bg-[#0b57d0] text-white rounded hover:bg-opacity-95 transition shadow-sm">Add</button>
          </div>
        </div>
      `;
      document.getElementById(`new-task-title-${status}`).focus();
    }

    function hideAddForm(status) {
      const containerId = status === 'To Do' ? 'todo-form-container' : (status === 'In Progress' ? 'inprogress-form-container' : 'done-form-container');
      const container = document.getElementById(containerId);

      container.innerHTML = `
        <button onclick="showAddForm('${status}')" class="w-full text-left text-xs text-[#0b57d0] hover:bg-white hover:bg-opacity-75 p-2 rounded-lg flex items-center gap-1.5 transition font-medium">
          <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 4v16m8-8H4"/>
          </svg>
          Add task
        </button>
      `;
    }

    function submitNewTask(status) {
      const titleInput = document.getElementById(`new-task-title-${status}`);
      const assigneeInput = document.getElementById(`new-task-assignee-${status}`);
      const title = titleInput.value.trim();
      if (!title) return;

      const newTask = {
        id: 'task-' + Date.now(),
        title: title,
        status: status,
        assignee: assigneeInput.value
      };

      const newState = [...currentTasks, newTask];
      saveSyncedState(newState);
      hideAddForm(status);
    }

    // Task State Transitions
    function moveTask(taskId, direction) {
      const updatedTasks = currentTasks.map(task => {
        if (task.id === taskId) {
          let newStatus = task.status;
          if (direction === 'next') {
            if (task.status === 'To Do') newStatus = 'In Progress';
            else if (task.status === 'In Progress') newStatus = 'Done';
          } else if (direction === 'prev') {
            if (task.status === 'Done') newStatus = 'In Progress';
            else if (task.status === 'In Progress') newStatus = 'To Do';
          }
          return { ...task, status: newStatus };
        }
        return task;
      });
      saveSyncedState(updatedTasks);
    }

    function deleteTask(taskId) {
      if (confirm("Are you sure you want to delete this task?")) {
        const updatedTasks = currentTasks.filter(task => task.id !== taskId);
        saveSyncedState(updatedTasks);
      }
    }

    // Init App
    renderCollaborators();
    loadSyncedState();

    // Short-polling interval (every 2 seconds) for live multi-user synchronization
    if (envId) {
      setInterval(loadSyncedState, 2000);
    }
  </script>
</body>
</html>
